import (
	"encoding/json"
	"fmt"
	nethttp "net/http"
	"time"
)

type Client struct {
	baseURL string
	client  *nethttp.Client
}

func NewClient(baseURL string) *Client {
	return &Client{
		baseURL: baseURL,
		client: &nethttp.Client{
			Timeout: 30 * time.Second,
		},
	}
}

func NewClientWithTimeout(baseURL string, timeout time.Duration) *Client {
	return &Client{
		baseURL: baseURL,
		client: &nethttp.Client{
			Timeout: timeout,
		},
	}
}
